import {
  type FrostConfig,
  initializeConfig,
  reconnect,
  WalletEventBridge,
  WalletRegistry,
} from "@rialo/frost-core";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import type { Context, ReactNode } from "react";
import { createContext, useContext, useEffect, useRef } from "react";

/** Context holding the Frost configuration */
const FrostContext: Context<FrostConfig | null> = createContext<FrostConfig | null>(null);

export interface FrostProviderProps {
  children: ReactNode;
  /**
   * Frost configuration object created with `createConfig()`.
   *
   * **Important:** Create the config outside of React components to ensure
   * it's only created once and remains stable across re-renders.
   *
   * @example
   * ```tsx
   * // config.ts
   * import { createConfig, getDefaultRialoClientConfig } from '@rialo/frost-core';
   *
   * export const config = createConfig({
   *   clientConfig: getDefaultRialoClientConfig('devnet'),
   * });
   *
   * // App.tsx
   * import { FrostProvider } from '@rialo/frost';
   * import { config } from './config';
   *
   * function App() {
   *   return (
   *     <FrostProvider config={config}>
   *       <YourApp />
   *     </FrostProvider>
   *   );
   * }
   * ```
   */
  config: FrostConfig;
  /** Optional external QueryClient (for sharing with app) */
  queryClient?: QueryClient;
}

/**
 * Provider component for Frost.
 * Initializes wallet discovery, event handling, and provides config to hooks.
 */
export function FrostProvider({
  children,
  config,
  queryClient: externalQueryClient,
}: Readonly<FrostProviderProps>): ReactNode {
  // Create QueryClient if not provided externally
  const queryClientRef = useRef<QueryClient | null>(null);
  if (!queryClientRef.current && !externalQueryClient) {
    queryClientRef.current = new QueryClient({
      defaultOptions: {
        queries: {
          staleTime: 1000 * 60, // 1 minute
          gcTime: 1000 * 60 * 5, // 5 minutes
        },
      },
    });
  }
  const queryClient = externalQueryClient ?? (queryClientRef.current as QueryClient);

  // Initialize registry, bridge, and auto-reconnect
  useEffect(() => {
    if (!config._registry) {
      const registry = new WalletRegistry(config);
      const bridge = new WalletEventBridge(config);

      initializeConfig(config, registry, bridge);
    }

    const shouldAutoReconnect =
      config.options.autoConnect &&
      config.store.state.walletName &&
      !config.store.state.userDisconnected;

    if (shouldAutoReconnect) {
      void reconnect(config);
    }
  }, [config]);

  return (
    <QueryClientProvider client={queryClient}>
      <FrostContext.Provider value={config}>{children}</FrostContext.Provider>
    </QueryClientProvider>
  );
}

/**
 * Hook to access the DappKit config.
 * Must be used within a FrostProvider.
 */
export function useFrostConfig(): FrostConfig {
  const config = useContext(FrostContext);
  if (!config) {
    throw new Error("useFrostConfig must be used within a FrostProvider");
  }
  return config;
}
