import type { FrostAppState } from "@rialo/frost-core";
import { PublicKey } from "@rialo/ts-cdk";
import { useQuery } from "@tanstack/react-query";
import { useStore } from "@tanstack/react-store";
import { useFrostConfig } from "../context";

export interface UseNativeBalanceOptions {
  /**
   * Address to query balance for.
   * Defaults to the active account address if not provided.
   */
  address?: string;

  /**
   * Number of decimal places for the native token.
   * Used for formatting the balance.
   * @default 9 (standard for Solana-based chains)
   */
  decimals?: number;
}

export interface UseNativeBalanceResult {
  /** Raw balance in kelvins/smallest unit */
  balance: bigint | undefined;

  /** Human-readable formatted balance (e.g., "1.5") */
  formatted: string | undefined;

  /** Whether the query is currently loading */
  isLoading: boolean;

  /** Whether the query is fetching (initial or refetch) */
  isFetching: boolean;

  /** Whether the query encountered an error */
  isError: boolean;

  /** Error object if query failed */
  error: Error | null;

  /** Manually trigger a refetch */
  refetch: () => void;
}

/**
 * Selector for active account address.
 * Defined at module level for stability.
 */
const selectAccountAddress = (state: FrostAppState): string | null => state.accountAddress;

/**
 * Formats a raw balance (in kelvins) to a human-readable string.
 */
function formatBalance(balance: bigint, decimals: number): string {
  const divisor = BigInt(10 ** decimals);
  const integerPart = balance / divisor;
  const fractionalPart = balance % divisor;

  const fractionalStr = fractionalPart.toString().padStart(decimals, "0");
  const trimmed = fractionalStr.replace(/0+$/, "");

  if (!trimmed) {
    return integerPart.toString();
  }

  return `${integerPart}.${trimmed}`;
}

/**
 * Hook to query the native token balance for an address.
 *
 * @example
 * ```tsx
 * function MyBalance() {
 *   const { balance, formatted, isLoading } = useNativeBalance();
 *   if (isLoading) return <div>Loading...</div>;
 *   return <div>Balance: {formatted} RIA</div>;
 * }
 * ```
 */
export function useNativeBalance(options: UseNativeBalanceOptions = {}): UseNativeBalanceResult {
  const { decimals = 9 } = options;

  const config = useFrostConfig();
  const activeAddress = useStore(config.store, selectAccountAddress);

  const address = options.address ?? activeAddress;

  const hasAddress = !!address;

  const query = useQuery({
    queryKey: ["frost", "nativeBalance", address, config.getChainId()],
    queryFn: (): Promise<bigint> => {
      if (!address) throw new Error("No address provided");

      return config.client.getBalance(PublicKey.fromString(address));
    },
    enabled: hasAddress,
  });

  return {
    balance: query.data,
    formatted: query.data !== undefined ? formatBalance(query.data, decimals) : undefined,
    isLoading: query.isLoading,
    isFetching: query.isFetching,
    isError: query.isError,
    error: query.error,
    refetch: () => {
      void query.refetch();
    },
  };
}
