import type { AccountEntity, FrostAppState } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useMemo } from "react";
import { useFrostConfig } from "../context";

/**
 * Selector for accounts map.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectAccountsMap = (state: FrostAppState): Map<string, AccountEntity> => state.accounts;

/**
 * Hook to get all known accounts.
 *
 * @returns Array of account entities (memoized)
 *
 * @example
 * ```tsx
 * function AccountList() {
 *   const accounts = useAccounts();
 *
 *   return (
 *     <ul>
 *       {accounts.map(acc => (
 *         <li key={acc.address}>{acc.address}</li>
 *       ))}
 *     </ul>
 *   );
 * }
 * ```
 */
export function useAccounts(): AccountEntity[] {
  const config = useFrostConfig();
  // Select just the Map reference - this is stable when accounts haven't changed
  const accountsMap = useStore(config.store, selectAccountsMap);

  // Memoize the array derivation
  return useMemo(() => Array.from(accountsMap.values()), [accountsMap]);
}
