import type { FrostAppState, WalletEntity } from "@rialo/frost-core";
import { useStore } from "@tanstack/react-store";
import { useMemo } from "react";
import { useFrostConfig } from "../context";

/**
 * Selector for wallets map.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectWalletsMap = (state: FrostAppState): Map<string, WalletEntity> => state.wallets;

/**
 * Selector for wallets ready state.
 * Defined at module level since it has no dependencies and never changes.
 */
const selectWalletsReady = (state: FrostAppState): boolean => state.wallets.size > 0;

/**
 * Hook to get sorted wallets list.
 * Wallets are sorted by priority (higher first) then by last connected time.
 *
 * @returns Sorted array of wallet entities (memoized)
 *
 * @example
 * ```tsx
 * function WalletList() {
 *   const wallets = useWallets();
 *
 *   return (
 *     <ul>
 *       {wallets.map(w => (
 *         <li key={w.name}>{w.name}</li>
 *       ))}
 *     </ul>
 *   );
 * }
 * ```
 */
export function useWallets(): WalletEntity[] {
  const config = useFrostConfig();
  // Select just the Map reference - this is stable when wallets haven't changed
  const walletsMap = useStore(config.store, selectWalletsMap);

  // Memoize the sorted array derivation
  return useMemo(
    () =>
      Array.from(walletsMap.values()).sort((a, b) => {
        const priorityDiff = (b.priority ?? 0) - (a.priority ?? 0);
        if (priorityDiff !== 0) return priorityDiff;
        return (b.lastConnectedAt ?? 0) - (a.lastConnectedAt ?? 0);
      }),
    [walletsMap]
  );
}

/**
 * Hook to check if wallets have been discovered.
 *
 * @returns True if at least one wallet has been discovered
 *
 * @example
 * ```tsx
 * function ConnectButton() {
 *   const walletsReady = useWalletsReady();
 *
 *   if (!walletsReady) return <div>Searching for wallets...</div>;
 *   return <button>Connect Wallet</button>;
 * }
 * ```
 */
export function useWalletsReady(): boolean {
  const config = useFrostConfig();
  return useStore(config.store, selectWalletsReady);
}
